# Cache for JWKS keys
_jwks_cache = {"keys": None, "fetched_at": 0, "ttl": 3600}

# Nonce/state expiry in seconds
NONCE_EXPIRY_SECONDS = 600  # 10 minutes


def get_jwks_keys():
    """Fetch and cache JWKS keys from the identity provider."""
    now = time.time()
    if _jwks_cache["keys"] and (now - _jwks_cache["fetched_at"]) < _jwks_cache["ttl"]:
        return _jwks_cache["keys"]

    try:
        resp = requests.get(OIDC_CONFIG["jwks_uri"], timeout=10)
        resp.raise_for_status()
        _jwks_cache["keys"] = resp.json()
        _jwks_cache["fetched_at"] = now
        return _jwks_cache["keys"]
    except requests.RequestException as e:
        app.logger.error(f"Failed to fetch JWKS keys: {e}")
        if _jwks_cache["keys"]:
            return _jwks_cache["keys"]
        raise


def generate_nonce():
    """Generate a cryptographically secure nonce."""
    return secrets.token_urlsafe(32)


def generate_state():
    """Generate a cryptographically secure state parameter for CSRF protection."""
    return secrets.token_urlsafe(32)


def validate_id_token(id_token, expected_nonce):
    """
    Validate the ID token according to OIDC spec.
    Verifies signature, issuer, audience, expiry, and nonce.
    """
    try:
        jwks = get_jwks_keys()

        # Decode header to find the key ID
        unverified_header = jwt.get_unverified_header(id_token)
        kid = unverified_header.get("kid")

        if not kid:
            app.logger.error("ID token missing 'kid' header")
            return None

        # Find the matching key
        rsa_key = None
        for key in jwks.get("keys", []):
            if key.get("kid") == kid:
                rsa_key = key
                break

        if not rsa_key:
            app.logger.error(f"No matching key found for kid: {kid}")
            return None

        # Verify and decode the token
        claims = jwt.decode(
            id_token,
            rsa_key,
            algorithms=["RS256"],
            audience=OIDC_CONFIG["client_id"],
            issuer=OIDC_CONFIG["issuer"],
            options={
                "verify_aud": True,
                "verify_iss": True,
                "verify_exp": True,
                "verify_iat": True,
            },
        )

        # CRITICAL: Verify the nonce to prevent replay attacks
        token_nonce = claims.get("nonce")
        if not token_nonce or token_nonce != expected_nonce:
            app.logger.error(
                "Nonce mismatch - possible replay attack. "
                f"Expected: {expected_nonce}, Got: {token_nonce}"
            )
            return None

        return claims

    except JWTError as e:
        app.logger.error(f"ID token validation failed: {e}")
        return None
    except Exception as e:
        app.logger.error(f"Unexpected error validating ID token: {e}")
        return None


def login_required(f):
    """Decorator to require authentication for routes."""

    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)

    return decorated_function


def cleanup_expired_nonces():
    """Remove expired nonces from the session store."""
    now = time.time()
    pending = session.get("pending_auth", {})
    expired_states = [
        state
        for state, data in pending.items()
        if now - data.get("created_at", 0) > NONCE_EXPIRY_SECONDS
    ]
    for state in expired_states:
        del pending[state]
    session["pending_auth"] = pending


