@app.route("/login")
def login():
    """Initiate OIDC authentication flow."""
    # Clean up any expired pending authentications
    cleanup_expired_nonces()

    # Generate state (CSRF protection) and nonce (replay protection)
    state = generate_state()
    nonce = generate_nonce()

    # Store state and nonce in session for validation during callback
    pending_auth = session.get("pending_auth", {})
    pending_auth[state] = {
        "nonce": nonce,
        "created_at": time.time(),
    }
    session["pending_auth"] = pending_auth

    # Build authorization URL with all required security parameters
    auth_params = {
        "client_id": OIDC_CONFIG["client_id"],
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "scope": "openid email profile",
        "response_type": "id_token",
        "state": state,
        "nonce": nonce,  # REQUIRED for implicit flow - prevents replay attacks
        "response_mode": "form_post",  # More secure than fragment for id_token
    }

    query_string = "&".join(
        f"{k}={requests.utils.quote(str(v))}" for k, v in auth_params.items()
    )
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?{query_string}"

    return redirect(auth_url)


@app.route("/callback", methods=["GET", "POST"])
def callback():
    """Handle the OIDC callback after authentication."""
    # For implicit flow with form_post, parameters come via POST
    # For fragment-based, they'd come via GET (handled by JS)
    if request.method == "POST":
        id_token = request.form.get("id_token")
        state = request.form.get("state")
        error = request.form.get("error")
        error_description = request.form.get("error_description")
    else:
        id_token = request.args.get("id_token")
        state = request.args.get("state")
        error = request.args.get("error")
        error_description = request.args.get("error_description")

    # Check for errors from the IdP
    if error:
        app.logger.error(
            f"OIDC authentication error: {error} - {error_description}"
        )
        return jsonify({"error": "Authentication failed", "details": error_description}), 401

    # Validate state parameter (CSRF protection)
    if not state:
        app.logger.error("Missing state parameter in callback")
        return jsonify({"error": "Invalid request - missing state"}), 400

    pending_auth = session.get("pending_auth", {})
    auth_data = pending_auth.get(state)

    if not auth_data:
        app.logger.error("Invalid or expired state parameter - possible CSRF attack")
        return jsonify({"error": "Invalid or expired authentication request"}), 400

    # Check if the auth request has expired
    if time.time() - auth_data["created_at"] > NONCE_EXPIRY_SECONDS:
        del pending_auth[state]
        session["pending_auth"] = pending_auth
        app.logger.error("Authentication request expired")
        return jsonify({"error": "Authentication request expired, please try again"}), 400

    expected_nonce = auth_data["nonce"]

    # Remove the used state/nonce (one-time use)
    del pending_auth[state]
    session["pending_auth"] = pending_auth

    if not id_token:
        app.logger.error("Missing id_token in callback")
        return jsonify({"error": "No ID token received"}), 400

    # Validate the ID token (signature, claims, and nonce)
    claims = validate_id_token(id_token, expected_nonce)

    if not claims:
        return jsonify({"error": "Invalid ID token"}), 401

    # Store user info in session
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email"),
        "name": claims.get("name"),
        "email_verified": claims.get("email_verified"),
        "authenticated_at": time.time(),
    }

    # Clear any pending auth data
    session.pop("pending_auth", None)

    # Redirect to the originally requested URL or dashboard
